INSERT INTO [leaders] ([id], [name], [phone], [introduction], [company], [image]) VALUES (1, '刘晋', '123465798', '刘晋，华盛顿州立大学计算机科学博士，上海海事大学教授，博士生导师；目前担任上海市思维科学研究会秘书长，上海市人工智能学会副秘书长，中国人工智能学会机器学习专委会委员，中国人工智能学会自然计算与数字智能城市专委会委员，上海市人工智能技术协会专家委员会委员，上海市科技专家库专家等学术兼职。自2009年至今已主持国家自然科学基金面上项目、国家社会科学基金重点项目、上海市科技创新行动计划重点项目等专业领域科研项目20余项，在国内外学术期刊与会议上发表SCI/EI检索科研论文80余篇，公开发明专利及软件著作权等40余项。主要研究方向：深度学习、情感计算、视觉与自然语言处理等。', 'SMU', NULL); GO
INSERT INTO [leaders] ([id], [name], [phone], [introduction], [company], [image]) VALUES (2, '龚沛朱', '2465543435', '龚沛朱，上海海事大学软件工程硕士，情感计算方向在读博士生，精通机器学习、深度学习等新一代人工智能技术，已发表SCI/EI检索学术论文2篇，公开国家发明专利3项，参加国家自然科学基金面上项目、国家社会科学基金重点项目等科研项目多项，获上海市普通高等学校优秀毕业生，“华为杯”第十六届中国研究生数学建模竞赛国家二等奖，上海海事大学硕士研究生学业奖学金一等奖，全国软件和信息技术专业人才大赛上海市三等奖，“创青春”全国大学生创业大赛上海市铜奖，“汇创青春”大学生创业大赛上海市三等奖等学科竞赛奖励。', 'SMU', NULL); GO
